  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラを本日より正式発足させることを決定する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "週次定例会議を毎週水曜日の10時より開催することを決定する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "システム移行方式として、拠点を分けて段階的に切り替えるB案（段階移行）を採用し、一括移行や並行稼働は見送ることを決定する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "データ移行の方針として、第1フェーズはマスタのみを実行し、トランザクション系（過去の入出庫履歴）の参照については当面旧システムを維持することを決定する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "開発ベンダーとしてコマツバ・ソリューションズを選定し、ハギワラ技研（納期理由）とツヅキシステム（予算超過理由）を見送ることを決定する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "本番リリースの目標日付を9月末から10月15日に変更し、段階移行によるスケジュール延長を正式に確定する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "システム切り替えの作業時間帯を平日夜間ではなく、土曜日の深夜帯に行うことを決定する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D8",
      "content": "新システムのユーザー権限設計において既存ロール定義を流用し、ロールの整理は稼働後の運用改善課題として別途行うことを決定する。",
      "decided_by": "桐生 遥"
    }
  ],
